prompt --application/pages/page_00020
begin
wwv_flow_api.create_page(
 p_id=>20
,p_user_interface_id=>wwv_flow_api.id(13548968093150363)
,p_name=>'Knockout intro'
,p_alias=>'INTRO'
,p_step_title=>'Knockout intro'
,p_autocomplete_on_off=>'OFF'
,p_javascript_file_urls=>wwv_flow_string.join(wwv_flow_t_varchar2(
'&LOC_CODEMIRROR.lib/codemirror.js',
'&LOC_CODEMIRROR.mode/xml/xml.js',
'&LOC_CODEMIRROR.mode/javascript/javascript.js',
'&LOC_CODEMIRROR.mode/css/css.js',
'&LOC_CODEMIRROR.mode/htmlmixed/htmlmixed.js'))
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var htmldb_delete_message=''"DELETE_CONFIRM_MSG"'';',
'var codemirrors = {};',
'var updateResult = function(execJS){',
'    ',
'    var $frame = $(''#p20-resultframe'');',
'    var doc = $frame[0].contentWindow.document;',
'    ',
'    var $body = $(''body'',doc);',
'    $body.html($(''#P20_HTML'').val());',
'    ',
'    var $head = $(''head'', doc);',
'    $head.append(''<style></style>'');',
'    var $style = $(''style'', doc);',
'    $style.html( $(''#P20_CSS'').val());',
'    ',
'    if(execJS==true){',
'        $body.append(''<script type="text/javascript" src="https://cdnjs.cloudflare.com/ajax/libs/knockout/3.4.2/knockout-min.js"><\/script>'');',
'        $body.append(''<script id="injectjs" type="application\/javascript"><\/script>'');',
'        var $script = $(''script#injectjs'', doc);',
'        $script.html( $(''#P20_JS'').val() );',
'',
'        var html = $(''html'', doc).html();',
'',
'        var iframe = document.getElementById(''p20-resultframe'');',
'        iframe = iframe.contentWindow || ( iframe.contentDocument.document || iframe.contentDocument);',
'        iframe.document.open();',
'        iframe.document.writeln(html);',
'        iframe.document.close();',
'    }',
'}'))
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'(function(){',
'    $(''textarea[data-codemirror]'').each( function(){',
'        var $this = $(this);',
'        var mode = $this.data(''codemirror-mode'');',
'        var editorname = $this.data(''codemirror'');',
'        codemirrors[ editorname ] = CodeMirror.fromTextArea( document.getElementById( $this.attr(''id'') ), {mode: mode} );',
'        codemirrors[ editorname ].on($this.data(''codemirror-event'') || ''change'', function(cm, o) {',
'            var pageItem = cm.getTextArea().id;',
'            $s( pageItem, cm.getValue() );',
'            updateResult(true);',
'        });',
'    });',
'    updateResult();',
'})();',
''))
,p_css_file_urls=>'&LOC_CODEMIRROR.lib/codemirror.css'
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
