prompt --application/pages/page_00035
begin
wwv_flow_api.create_page(
 p_id=>35
,p_user_interface_id=>wwv_flow_api.id(13548968093150363)
,p_name=>'Tabular Form 2'
,p_step_title=>'Tabular Form 2'
,p_reload_on_submit=>'A'
,p_autocomplete_on_off=>'OFF'
,p_javascript_file_urls=>wwv_flow_string.join(wwv_flow_t_varchar2(
'&LOC_ORACLEJET.js/libs/knockout/knockout-&VER_KNOCKOUT..js',
'#APP_IMAGES#knockout-pre-rendered.js'))
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var htmldb_delete_message=''"DELETE_CONFIRM_MSG"'';',
'',
'function ProductViewModel() {',
'  var self = this;',
'  self.name = ko.observable();',
'  self.price = ko.observable();',
'  self.qty = ko.observable();',
'  ',
'  self.subtotal = ko.computed(function(){',
'      return (parseInt("0" + self.price()) * parseInt("0" + self.qty())) + ''.00'';',
'  }, self);',
'',
'}',
'function ForeachViewModel() {',
'  var self = this;',
'  ',
'  self.products = ko.observableArray();',
'',
'  this.list_total = ko.pureComputed(function(){',
'      var total = 0;',
'      $.each(self.products(), function(index, value) { total += parseInt("0" + value.price()); });',
'      return total;',
'  });',
'',
'  this.total = ko.pureComputed(function(){',
'      var total = 0;',
'      $.each(self.products(), function(index, value) { total += parseInt("0" + value.subtotal()); });',
'      return total;',
'  });',
'',
'  this.totalqty = ko.pureComputed(function(){',
'      var total = 0;',
