,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'//convert items into html5 items',
'$(''input[data-html-type]'').each(function(){var $this=$(this); $this.attr("type", $this.data(''html-type''))});',
'',
'var $rowContainer = $(this.triggeringElement).find(".t-Report-report tbody"),',
'    rowCount = $rowContainer.find("tr").length;',
'',
'// Add ko foreach bind',
'$rowContainer.attr("data-bind",  "foreachInit: { name: ''productTemplate'', data: products }");',
'',
'// Add column total bind',
'$rowContainer.find("tr:last").find(''[headers="LIST_PRICE"]'').html(',
'  ''<b><span data-bind="text: $parent.list_total"></span></b>''',
');',
'// Add column total-items bind',
'$rowContainer.find("tr:last").find(''[headers="QTY"]'').html(',
'  ''<b><span data-bind="text: $parent.totalqty"></span></b>''',
');',
'// Add column total bind',
'$rowContainer.find("tr:last").find(''[headers="TOTAL"]'').html(',
'  ''<b><span data-bind="text: $parent.total"></span></b>''',
');',
'',
'// Don''t count the Totals row',
'//rowCount--;',
'',
'viewModel = new ForeachViewModel();',
'// pre populate position for all the data',
'for (var i=0; i<rowCount; i++) {',
'  viewModel.products.push(new ProductViewModel());',
'}',
'',
'ko.applyBindings(viewModel);'))
);
