wwv_flow_api.create_page(
 p_id=>42
,p_user_interface_id=>wwv_flow_api.id(13548968093150363)
,p_name=>'EMP Letter jQuery details'
,p_page_mode=>'MODAL'
,p_step_title=>'EMP Letter jQuery details'
,p_autocomplete_on_off=>'OFF'
,p_javascript_file_urls=>'&LOC_JQUERYUI.ui/jquery-ui.js'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var htmldb_delete_message=''"DELETE_CONFIRM_MSG"'';',
'',
'function doRefresh() {',
'    console.log(''doRefresh'');',
'    $(''#p42-cr-texts'').trigger(''apexrefresh'');',
'    $(''#p42-cr-letter'').trigger(''apexrefresh'');',
'}',
'',
'function doSortStop(event, ui) {',
'    console.log(''doSortStop'');',
'    saveLetterTexts();    ',
'}',
'',
'function setSortable() {',
'    console.log(''setSortable'');',
'    try { $(''.sortable'').sortable(''destroy''); } catch(err) { void(0); }',
'    $(''.sortable'').sortable({',
'        handle: ''.draghandle'',',
'        placeholder: ''portlet-placeholder'',',
'        revert: true,',
'        stop: function(event, ui) {',
'            doSortStop(event, ui);',
'        }',
'    });',
'}',
'',
'function setDraggable(){',
'    console.log(''setDraggable'');',
'    try { $(''div.draggable'').draggable(''destroy''); } catch(err) { void(0); }',
'    $(''div.draggable'').draggable( {',
'        appendTo: ''body'',',
'        connectToSortable: ''.sortable'',',
'        containment: "window",',
'        helper: ''clone'',',
'        /*',
'        helper: function(event) {',
'            return $(event.target).clone().css({',
'                width: $(event.target).width(),',
'                backgroundColor: ''#ffffff'',',
'                padding: ''2px 5px''',
'            });',
'        },/**/',
'        revert: false,',
'        scroll: false',
'    });',
'}',
'',
'function saveLetterTexts() {',
'    if($(''.employeetexts div[data-sltt-id]'').size()==0) {',
'        console.log(''delete LetterTexts: '' + $v(''P42_EMPNO''));',
'        // no elements present, we must remove all instances',
'        apex.server.process(',
'            ''DELETE_ELTT'',',
'            { //pData',
'                x01: $v(''P42_EMPNO'')',
'            },',
'            { //pOptions',
'                dataType: ''text'',',
'                async: false,',
'                succes: doRefresh()',
'            }',
'        );',
'    } else {',
'        console.log(''Save LetterTexts: '' + $(''.employeetexts div[data-eltt-id]'').size());',
'        $(''.employeetexts div[data-sltt-id]'').each(',
'            function(){',
'                //debugger;',
'                var sltt_id  = $(this).attr(''data-sltt-id'');',
'                if ( sltt_id != 0 ) {',
'                    var ordernr   = $(this).index();',
'                    var lettertxt = $(this).find(''.eltt_tekst'').html();',
'                    var empno     = $v(''P42_EMPNO'');',
'                    // prepare tekst',
'                    if(lettertxt) {',
'                        lettertxt = lettertxt.replace(''<div>'', ''\r\n'');',
'                        lettertxt = lettertxt.replace(''<br>'', ''\r\n'');',
'                        lettertxt = lettertxt.replace(''<\div>'', '''');',
'                    }',
'                    // end prepare tekst       ',
'                    apex.server.process(',
'                        ''SAVE_ELTT'',',
'                        { // pData',
'                            x01  : empno,',
'                            x02  : sltt_id,',
'                            x03  : ordernr,',
'                            x04  : lettertxt',
'                        },',
'                        { //pOptions',
'                            dataType : ''text'',',
'                            async    : false,',
'                            success  : function(pData){',
'                                if(pData!="") {alert(pData);} else {doRefresh();}',
'                            }',
'                        }',
'                    );',
'                }',
'            }',
'        );',
'    }',
'    doRefresh();',
'}'))
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
'a[data-delete-sltt-id]{cursor: pointer; float: right;}',
'',
'a[data-delete-sltt-id="-1"] {display:  none;}',
'',
'.draghandle { cursor: move; }',
'',
'.lettertext {',
'    border: 1px solid #cecece;',
'    border-radius: 5px;',
'    margin: 3px 0 3px 0;',
'    padding: 2px 5px;',
'}',
'',
'.eltt_tekst { ',
'    width: 95%; ',
'    text-align: justify;',
'    padding: 5px;',
'    white-space: pre-wrap;',
'}',
'/*',
'#042-cr-letter {',
'    max-height: 475px !important;',
'    border: 1px solid #cecece;',
'    padding:  6px;',
'    border-radius: 1px;',
'    margin-bottom: 0px;',
'}',
'/**/',
