,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select sl.code                     as SLTT_CODE',
',      sl.id                       as SLTT_ID',
'from   standard_lettertexts sl',
'  left join emp_lettertexts lt on lt.std_lettertext_id = sl.id and lt.empno = :P42_EMPNO--7788',
'where  lt.id is null',
' and (:P42_SEARCH is null or instr(lower(sl.code), lower(:P42_SEARCH)) > 0)',
'order by sl.code'))
