,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select sltt.id as sltt_id',
',      eltt.id as eltt_id',
',      sltt.code',
',      coalesce(eltt.lettertext, sltt.lettertext, to_clob('' '')) as brieftekst',
',      eltt.ordernr',
'from   emp_lettertexts eltt',
'  join standard_lettertexts sltt on sltt.id = eltt.std_lettertext_id',
'where  eltt.empno = :P42_EMPNO',
'union all',
'select -1           as sltt_id',
',      -1           as eltt_id',
',      null         as code',
',      to_clob('' '') as brieftekst',
',      9999         as volgorde',
'from   dual',
'where not exists (select 1 from emp_lettertexts eltt where eltt.empno = :P42_EMPNO)',
'order by ordernr'))
