'var htmldb_delete_message=''"DELETE_CONFIRM_MSG"'';',
'',
'function vmText( id, std_lettertext_id, code, defaulttext, lettertext, ordernr ) {',
'    var self = this;',
'    self.id                = id;',
'    self.std_lettertext_id = std_lettertext_id;',
'    self.code              = code;',
'    self.defaulttext       = defaulttext;',
'    self.lettertext        = ko.observable(lettertext);',
'    self.ordernr           = ko.observable(ordernr);',
'}',
'',
'function vmTexts() {',
'    var self = this,',
'        text;',
'    self.standardtexts = ko.observableArray();',
'    self.standardtexts.id = ''standardtexts'';',
'    self.employeetexts = ko.observableArray();',
'    self.employeetexts.id = ''lettertexts'';',
'    self.moveStandardText = function(index) {',
'        self.employeetexts.push(self.standardtexts[index]);',
'        self.standardtexts.splice(index, 1);',
'    };',
'    self.moveLetterText = function(index) {',
'        self.standardtexts.push(self.employeetexts[index]);',
'        self.employeetexts.splice(index, 1);',
'    };',
'    self.readServerResponse = function(pData) {',
'        for (ii=0; ii<pData.length; ii++) {',
'            text = new vmText(  pData[ii].ID',
'                              , pData[ii].STD_LETTERTEXT_ID',
'                              , pData[ii].CODE',
'                              , pData[ii].DEFAULTTEXT',
'                              , pData[ii].LETTERTEXT',
'                             );',
'            if(pData[ii].TEXTTYPE == ''STANDARDTEXT'') {',
'                self.standardtexts.push( text );',
'            } else {',
'                self.employeetexts.push( text );',
'            }            ',
'        }',
'    };',
'    self.updateLastAction = function(arg) {',
'        console.log("Moved " + arg.item.code',
'                    + " from " + arg.sourceParent.id + " (index " + (arg.sourceIndex + 1) + ")" ',
'                    + " to "   + arg.targetParent.id + " (index " + (arg.targetIndex + 1) + ")"',
'                   );',
'    };',
'}',
'',
'ko.bindingHandlers.contentEditable = {',
'    init: function(element, valueAccessor) {',
'        var value = valueAccessor();',
'',
'        function setValue(){',
'            if (ko.isWriteableObservable(value)) {',
'                value(this.innerHTML);',
'            }',
'        };                ',
'',
'        element.innerHTML = value(); //set initial value',
'        element.contentEditable = true; //mark contentEditable true',
'        element.addEventListener(''keyup'', setValue); //add keyup listener',
'    }',
'};'))
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'vm = new vmTexts();',
'',
'apex.server.process ( "GET_LETTERTEXTS", {',
'    pageItems: ["P46_EMPNO"]',
'},{',
'    success: function( pData ) {',
'        vm.readServerResponse(pData);',
'    }',
'});',
'',
'//ko.bindingHandlers.sortable.beforeMove = vm.verifyAssignments;',
'ko.bindingHandlers.sortable.afterMove = vm.updateLastAction;',
'',
'ko.applyBindings(vm);'))
,p_css_file_urls=>'&LOC_JQUERYUI.jquery-ui-apex.css'
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
'.sdtt {',
'    border: 1px solid lightblue;',
'    border-radius: 4px;',
'    margin-bottom: 3px;',
'}',
'.draggable, .draghandle {cursor: move;}',
'.draghandle a {cursor: pointer; float: right;}',
'.dett_code.draghandle span {',
'    border: 1px solid #cecece;',
'    padding: 3px;',
'    border-radius: 5px;',
'    margin: 5px 5px 0 0;',
'    display: inline-block;',
'}'))
,p_page_template_options=>'#DEFAULT#:ui-dialog--stretch'
,p_dialog_width=>'1500'
,p_protection_level=>'C'
,p_page_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'#APP_IMAGES#knockout-pre-rendered#MIN#.js',
''))
,p_last_updated_by=>'R.MARTENS@SMART4SOLUTIONS.NL'
