,p_process_sequence=>10
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'GET_LETTERTEXTS'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    c sys_refcursor;',
'begin',
'',
'  open c for select ''EMPLOYEETEXT''         as texttype',
'                   ,lrtt.id                as id',
'                   ,lrtt.std_lettertext_id as std_lettertext_id',
'                   ,sdlt.lettertext        as defaulttext',
'                   ,lrtt.lettertext        as lettertext',
'                   ,lrtt.ordernr           as ordernr',
'                   ,sdlt.code              as code',
'             from   emp_lettertexts      lrtt',
'             join   standard_lettertexts sdlt on sdlt.id = lrtt.std_lettertext_id',
'             where  lrtt.empno = :P46_EMPNO',
'             union all',
'             select ''STANDARDTEXT''         as texttype',
'                   ,null                   as id',
'                   ,sdlt.id                as std_lettertext_id',
'                   ,sdlt.lettertext        as defaulttext',
'                   ,sdlt.lettertext        as lettertext',
'                   ,0                      as ordernr',
'                   ,sdlt.code              as code',
'             from   standard_lettertexts sdlt',
'             left   join emp_lettertexts lrtt',
'             on     (lrtt.std_lettertext_id = sdlt.id and lrtt.empno = :P46_EMPNO)',
'             where  lrtt.id is null',
'             order  by texttype desc',
'                      ,ordernr',
'                      ,code;',
'                          ',
'  apex_json.write(c);',
'  ',
'end;',
''))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
end;
